export interface UXAnalysis {
  userJourney: string[];
  clearElements: string[];
  confusionPoints: string[];
  visualHierarchyScore: number;
  hierarchyAnalysis: string;
  recommendations: string[];
}

export interface Persona {
  name: string;
  role: string;
  age: number;
  traits: string[];
  goals: string;
  frustrations: string;
}

export enum AnalysisStatus {
  IDLE = 'IDLE',
  UPLOADING = 'UPLOADING',
  ANALYZING = 'ANALYZING',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { UXAnalysis } from "../types";
import { SYSTEM_PROMPT } from "../constants";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async analyzePrototype(images: string[]): Promise<UXAnalysis> {
    const model = 'gemini-3-flash-preview';

    const parts = images.map(img => ({
      inlineData: {
        mimeType: 'image/png',
        data: img.split(',')[1] // Assuming base64 data URL
      }
    }));

    const response = await this.ai.models.generateContent({
      model,
      contents: {
        parts: [
          { text: SYSTEM_PROMPT },
          ...parts
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            userJourney: { type: Type.ARRAY, items: { type: Type.STRING } },
            clearElements: { type: Type.ARRAY, items: { type: Type.STRING } },
            confusionPoints: { type: Type.ARRAY, items: { type: Type.STRING } },
            visualHierarchyScore: { type: Type.NUMBER },
            hierarchyAnalysis: { type: Type.STRING },
            recommendations: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["userJourney", "clearElements", "confusionPoints", "visualHierarchyScore", "hierarchyAnalysis", "recommendations"]
        }
      }
    });

    if (!response.text) {
      throw new Error("No response from Gemini");
    }

    try {
      return JSON.parse(response.text.trim()) as UXAnalysis;
    } catch (e) {
      console.error("Failed to parse JSON", response.text);
      throw new Error("Invalid response format from AI");
    }
  }
}

