import { GoogleGenAI, Type } from "@google/genai";
import { UXAnalysis } from "../types";
import { SYSTEM_PROMPT } from "../constants";

export class GeminiService {
  // Fix: Initialize GoogleGenAI within the method using process.env.API_KEY directly and use gemini-3-pro-preview for advanced multimodal analysis.
  async analyzePrototype(images: string[]): Promise<UXAnalysis> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-pro-preview';

    const parts = images.map(img => ({
      inlineData: {
        mimeType: 'image/png',
        data: img.split(',')[1] // Extracting base64 data from the data URL
      }
    }));

    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [
          { text: SYSTEM_PROMPT },
          ...parts
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            userJourney: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: 'Steps in the user journey.'
            },
            clearElements: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: 'Elements that are clear to the user.'
            },
            confusionPoints: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: 'Points where the user might get confused.'
            },
            visualHierarchyScore: { 
              type: Type.NUMBER,
              description: 'Score from 0 to 100 representing visual hierarchy quality.'
            },
            hierarchyAnalysis: { 
              type: Type.STRING,
              description: 'Short textual analysis of the visual hierarchy.'
            },
            recommendations: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: 'Expert recommendations for improvement.'
            }
          },
          required: ["userJourney", "clearElements", "confusionPoints", "visualHierarchyScore", "hierarchyAnalysis", "recommendations"],
          propertyOrdering: ["userJourney", "clearElements", "confusionPoints", "visualHierarchyScore", "hierarchyAnalysis", "recommendations"]
        }
      }
    });

    if (!response.text) {
      throw new Error("No response from Gemini");
    }

    try {
      return JSON.parse(response.text.trim()) as UXAnalysis;
    } catch (e) {
      console.error("Failed to parse JSON", response.text);
      throw new Error("Invalid response format from AI");
    }
  }
}

