export const GENERATE_SYSTEM_PROMPT = (persona: PersonaOption, intent: IntentOption) => `
אתה מומחה UX/UI בעל 15 שנות ניסיון. אתה מנתח מסכים (בודד או Flow) לפי מתודולוגיה קפדנית של 9 שלבים.

הפרסונה שלך לניתוח זה:
שם: ${persona.name}
תפקיד: ${persona.role}
תיאור: ${persona.description}

כוונת המשתמש (Intent):
${intent.label} - ${intent.description}

עליך לנתח את התמונות המצורפות ולספק דוח JSON מלא לפי השלבים הבאים בלבד:

שלב 1: הגדרת הקשר (Context Definition)
מה מטרת המסך? באיזה שלב בפאנל המשתמש נמצא? מה רמת המחויבות הרגשית?

שלב 2: ניתוח היררכיית קשב (Attention Hierarchy)
מה הדבר הראשון והשני שהעין רואה? האם ההיררכיה הויזואלית משרתת את העסקית?

שלב 3: עומס קוגניטיבי (Cognitive Load)
ניתוח עומס אינפורמטיבי, השוואתי, החלטתי (Hick's Law).

שלב 4: ניתוח רגשי (Emotional Friction)
האם מופעל Loss Aversion? לחץ זמן? האם המסך מרגיע או מלחיץ?

שלב 5: חיכוך התנהגותי (Behavioral Friction)
שדות מיותרים, הסחות דעת, נקודות נטישה משוערות.

שלב 6: ניתוח אמון (Trust & Risk)
שקיפות, אבטחה נתפסת, בירוקרטיה.

שלב 7: Event & Funnel Hypothesis
אילו KPI למדוד? איפה יהיה ה-Drop-off המרכזי?

שלב 8: הצעת פתרונות ממוסגרים
לכל בעיה מהותית, ציין רכיב, הבעיה, למה זו בעיה, סיכון לנטישה, ופתרון.

שלב 9: תעדוף (Impact vs Effort)
חלק את הפתרונות ל-Quick wins, Medium impact, Structural redesign.

החזר אך ורק JSON תקין התואם לסקריפט ה-Schema המבוקש.
`;

import { GoogleGenAI, Type } from "@google/genai";
import { UXMethodologyResult, PersonaOption, IntentOption } from "../types";
import { GENERATE_SYSTEM_PROMPT } from "../constants";

export class GeminiService {
  async analyzeFlow(images: string[], persona: PersonaOption, intent: IntentOption): Promise<UXMethodologyResult> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-pro-preview';

    const parts = images.map(img => ({
      inlineData: {
        mimeType: 'image/png',
        data: img.split(',')[1] 
      }
    }));

    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [
          { text: GENERATE_SYSTEM_PROMPT(persona, intent) },
          ...parts
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            // Step 1
            contextGoal: { type: Type.STRING, description: "Primary goal of the screen/flow" },
            userCommitmentLevel: { type: Type.STRING, description: "Emotional commitment level" },

            // Step 2
            firstElementSeen: { type: Type.STRING, description: "First visual element noticed" },
            secondElementSeen: { type: Type.STRING, description: "Second visual element noticed" },
            hierarchyMatch: { type: Type.BOOLEAN, description: "Does visual hierarchy match business goals?" },
            hierarchyAnalysis: { type: Type.STRING, description: "Detailed hierarchy analysis" },

            // Step 3
            cognitiveLoadAnalysis: { type: Type.STRING, description: "Analysis of information/decision load" },

            // Step 4
            emotionalAnalysis: { type: Type.STRING, description: "Emotional friction, stress, or calmness" },

            // Step 5
            frictionPoints: { type: Type.ARRAY, items: { type: Type.STRING }, description: "List of behavioral friction points" },
            estimatedDropOffRate: { type: Type.STRING, description: "Estimated abandonment percentage or level" },

            // Step 6
            trustAnalysis: { type: Type.STRING, description: "Trust signals and risk analysis" },

            // Step 7
            kpiToMeasure: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Suggested KPIs or events to track" },
            dropOffHypothesis: { type: Type.STRING, description: "Hypothesis on where drop-off happens" },

            // Step 8
            solutions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  component: { type: Type.STRING },
                  problem: { type: Type.STRING },
                  whyItsAProblem: { type: Type.STRING },
                  abandonmentRisk: { type: Type.STRING },
                  solution: { type: Type.STRING }
                },
                required: ["component", "problem", "whyItsAProblem", "abandonmentRisk", "solution"]
              }
            },

            // Step 9
            prioritization: {
              type: Type.OBJECT,
              properties: {
                quickWins: { type: Type.ARRAY, items: { type: Type.STRING } },
                mediumImpact: { type: Type.ARRAY, items: { type: Type.STRING } },
                structuralRedesign: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["quickWins", "mediumImpact", "structuralRedesign"]
            }
          },
          required: [
            "contextGoal", "userCommitmentLevel", 
            "firstElementSeen", "secondElementSeen", "hierarchyMatch", "hierarchyAnalysis",
            "cognitiveLoadAnalysis", "emotionalAnalysis", 
            "frictionPoints", "estimatedDropOffRate",
            "trustAnalysis",
            "kpiToMeasure", "dropOffHypothesis",
            "solutions", "prioritization"
          ]
        }
      }
    });

    if (!response.text) {
      throw new Error("No response from Gemini");
    }

    try {
      return JSON.parse(response.text.trim()) as UXMethodologyResult;
    } catch (e) {
      console.error("Failed to parse JSON", response.text);
      throw new Error("Invalid response format from AI");
    }
  }
}

export const geminiService = new GeminiService();

import React, { useState, useRef } from 'react';
import { AnalysisStatus, UXMethodologyResult, PersonaOption, IntentOption } from './types';
import { PERSONAS, INTENTS } from './constants';
import { geminiService } from './services/geminiService';
import AnalysisResult from './components/AnalysisResult';

const App: React.FC = () => {
  const [status, setStatus] = useState<AnalysisStatus>(AnalysisStatus.IDLE);
  const [images, setImages] = useState<string[]>([]);
  const [analysis, setAnalysis] = useState<UXMethodologyResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Selection State
  const [selectedPersona, setSelectedPersona] = useState<PersonaOption>(PERSONAS[0]);
  const [selectedIntent, setSelectedIntent] = useState<IntentOption>(INTENTS[0]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    // Limit to 3 images total
    const remainingSlots = 3 - images.length;
    if (remainingSlots <= 0) {
      alert("ניתן להעלות עד 3 מסכים לניתוח Flow");
      return;
    }

    const filesToProcess = files.slice(0, remainingSlots);

    setStatus(AnalysisStatus.UPLOADING);
    const readers = filesToProcess.map(file => {
      return new Promise<string>((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(file);
      });
    });

    Promise.all(readers).then(dataUrls => {
      setImages(prev => [...prev, ...dataUrls]);
      setStatus(AnalysisStatus.IDLE);
    });
  };

  const startAnalysis = async () => {
    if (images.length === 0) return;

    setStatus(AnalysisStatus.ANALYZING);
    setError(null);

    try {
      const result = await geminiService.analyzeFlow(images, selectedPersona, selectedIntent);
      setAnalysis(result);
      setStatus(AnalysisStatus.COMPLETED);
    } catch (err: any) {
      setError(err.message || 'אירעה שגיאה בניתוח הפרוטוטיפ');
      setStatus(AnalysisStatus.ERROR);
    }
  };

  const reset = () => {
    setImages([]);
    setAnalysis(null);
    setStatus(AnalysisStatus.IDLE);
    setError(null);
  };

  return (
    <div className="min-h-screen pb-20 bg-slate-50">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-indigo-200">
              9
            </div>
            <div>
              <h1 className="text-xl font-extrabold tracking-tight text-slate-800 leading-none">UX Steps</h1>
              <span className="text-xs text-indigo-600 font-bold tracking-widest uppercase">Expert Analyzer</span>
            </div>
          </div>
          <div className="hidden md:flex gap-6 text-sm font-medium text-slate-500">
            <span className="text-slate-400">Context</span>
            <span className="text-slate-400">Hierarchy</span>
            <span className="text-slate-400">Friction</span>
            <span className="text-indigo-600 font-bold">Action</span>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 pt-12">
        {/* Intro */}
        {!analysis && (
          <div className="text-center mb-12 animate-in fade-in zoom-in duration-500">
            <h2 className="text-4xl md:text-5xl font-black text-slate-900 mb-4">
              ניתוח UX במתודולוגיית <span className="text-indigo-600">9 השלבים</span>
            </h2>
            <p className="text-lg text-slate-500 max-w-2xl mx-auto leading-relaxed">
              העלה עד 3 מסכים (Flow), בחר פרסונה וכוונת משתמש, וקבל ניתוח אסטרטגי עמוק הכולל היררכיית קשב, עומס קוגניטיבי ומטריצת פתרונות.
            </p>
          </div>
        )}

        {/* Configuration Section (Only show if no analysis yet) */}
        {!analysis && (
          <div className="grid md:grid-cols-2 gap-6 mb-8">
            {/* Persona Selection */}
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
              <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                👤 בחר פרסונה
              </h3>
              <div className="space-y-3">
                {PERSONAS.map(p => (
                  <div 
                    key={p.id}
                    onClick={() => setSelectedPersona(p)}
                    className={`p-4 rounded-xl border-2 cursor-pointer transition-all ${selectedPersona.id === p.id ? 'border-indigo-600 bg-indigo-50' : 'border-slate-100 hover:border-indigo-200'}`}
                  >
                    <div className="flex justify-between items-center mb-1">
                      <span className="font-bold text-slate-900">{p.name}</span>
                      <span className="text-xs font-semibold text-slate-500 bg-white px-2 py-1 rounded-md border border-slate-100">{p.role}</span>
                    </div>
                    <p className="text-sm text-slate-600">{p.description}</p>
                  </div>
                ))}
              </div>
            </div>

            {/* Intent Selection */}
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
              <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                🎯 כוונת משתמש (Intent)
              </h3>
              <div className="space-y-3">
                {INTENTS.map(intent => (
                  <div 
                    key={intent.id}
                    onClick={() => setSelectedIntent(intent)}
                    className={`p-4 rounded-xl border-2 cursor-pointer transition-all ${selectedIntent.id === intent.id ? 'border-indigo-600 bg-indigo-50' : 'border-slate-100 hover:border-indigo-200'}`}
                  >
                    <div className="font-bold text-slate-900 mb-1">{intent.label}</div>
                    <p className="text-sm text-slate-600">{intent.description}</p>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* Upload & Action Area */}
        <div className={`bg-white p-8 rounded-3xl shadow-xl border border-slate-100 text-center transition-all duration-500 ${analysis ? 'mb-8' : ''}`}>
          {images.length === 0 ? (
            <div 
              onClick={() => fileInputRef.current?.click()}
              className="group border-2 border-dashed border-slate-300 rounded-2xl p-12 hover:border-indigo-400 hover:bg-indigo-50 transition-all cursor-pointer"
            >
              <div className="w-16 h-16 bg-slate-100 rounded-2xl flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                <span className="text-3xl">📤</span>
              </div>
              <h4 className="text-xl font-bold text-slate-800 mb-2">העלאת מסכים לניתוח (עד 3)</h4>
              <p className="text-slate-400">תומך ב-JPG, PNG. העלה מסך בודד או רצף פעולות.</p>
            </div>
          ) : (
            <div>
              {!analysis && (
                 <h3 className="text-lg font-bold mb-6 text-slate-700">מסכים שנבחרו ({images.length}/3)</h3>
              )}

              <div className="flex flex-wrap gap-4 justify-center mb-8">
                {images.map((img, i) => (
                  <div key={i} className="relative group">
                    <div className="absolute top-2 left-2 bg-black/70 text-white text-xs px-2 py-1 rounded-md z-10">
                      מסך {i + 1}
                    </div>
                    <img src={img} className="w-40 h-72 object-cover rounded-xl border-2 border-slate-200 shadow-sm transition-transform hover:scale-105 bg-slate-100" />
                    {!analysis && (
                      <button 
                        onClick={() => setImages(prev => prev.filter((_, idx) => idx !== i))}
                        className="absolute -top-2 -right-2 w-8 h-8 bg-rose-500 text-white rounded-full flex items-center justify-center text-sm shadow-md hover:bg-rose-600 transition-colors"
                      >
                        ✕
                      </button>
                    )}
                  </div>
                ))}

                {images.length < 3 && !analysis && (
                  <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="w-40 h-72 border-2 border-dashed border-slate-300 rounded-xl flex flex-col items-center justify-center text-slate-400 hover:border-indigo-400 hover:text-indigo-400 transition-colors hover:bg-slate-50"
                  >
                    <span className="text-4xl mb-2">+</span>
                    <span className="text-sm font-medium">הוסף מסך</span>
                  </button>
                )}
              </div>

              {!analysis && (
                <div className="flex gap-4 justify-center animate-in slide-in-from-bottom-2">
                  <button
                    disabled={status === AnalysisStatus.ANALYZING}
                    onClick={startAnalysis}
                    className={`px-10 py-4 bg-indigo-600 text-white rounded-2xl font-bold text-lg shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all flex items-center gap-3 ${status === AnalysisStatus.ANALYZING ? 'opacity-70 cursor-not-allowed' : ''}`}
                  >
                    {status === AnalysisStatus.ANALYZING ? (
                      <>
                        <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                        מעבד מתודולוגיה...
                      </>
                    ) : (
                      <>
                        <span>🚀</span>
                        <span>בצע ניתוח 9 שלבים</span>
                      </>
                    )}
                  </button>
                  <button
                    onClick={reset}
                    className="px-8 py-4 bg-slate-100 text-slate-600 rounded-2xl font-bold hover:bg-slate-200 transition-colors"
                  >
                    איפוס הכל
                  </button>
                </div>
              )}

              {analysis && (
                 <button
                 onClick={reset}
                 className="mt-4 px-6 py-2 bg-slate-100 text-slate-600 rounded-xl font-bold hover:bg-slate-200 transition-colors text-sm"
               >
                 🔄 התחל ניתוח חדש
               </button>
              )}
            </div>
          )}

          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            multiple 
            accept="image/*" 
            className="hidden" 
          />
        </div>

        {/* Loading/Error States */}
        {error && (
          <div className="mt-8 p-4 bg-rose-50 border border-rose-200 text-rose-700 rounded-2xl flex items-center gap-3 animate-pulse">
            <span>⚠️</span>
            <p className="font-medium">{error}</p>
          </div>
        )}

        {/* Results */}
        {analysis && <AnalysisResult analysis={analysis} />}
      </main>

      {/* Footer */}
      <footer className="mt-20 text-center text-slate-400 text-sm pb-8">
        <p>© 2025 UX 9-Step Expert Analyzer</p>
      </footer>
    </div>
  );
};

export default App;
